    public List<CollateralDisposalRecordedEventResponse> getCollateralDisposalRecordedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(COLLATERALDISPOSALRECORDED_EVENT, transactionReceipt);
        ArrayList<CollateralDisposalRecordedEventResponse> responses = new ArrayList<CollateralDisposalRecordedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            CollateralDisposalRecordedEventResponse typedResponse = new CollateralDisposalRecordedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.repaymentNo = (byte[]) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.loanNo = (byte[]) eventValues.getIndexedValues().get(1).getValue();
            typedResponse.disposalMethod = (String) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.disposalAmount = (BigInteger) eventValues.getNonIndexedValues().get(1).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

